  const lines: string[] = [`## [${entry.version}] - ${entry.date}`, ""];

  if (entry.breaking.length > 0) {
    lines.push("### BREAKING CHANGES", "");
    for (const b of entry.breaking) lines.push(`- ${b}`);
    lines.push("");
  }
